1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with 2 live neighbors (survival)", () => {
15	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toContainEqual([0, 1]);
16	  });
17	  it("should keep alive a live cell with 3 live neighbors (survival)", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toContainEqual([1, 0]);
19	  });
20	  it.todo("should kill a live cell with 4 live neighbors (overpopulation)");
21	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
22	  it.todo("should keep a block pattern unchanged (still life)");
23	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
24	});
25

1	type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  (x !== otherX || y !== otherY) &&
5	  Math.abs(otherX - x) <= 1 &&
6	  Math.abs(otherY - y) <= 1;
7	
8	const countLiveNeighbors = (cell: Cell, livingCells: Cell[]): number =>
9	  livingCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const survives = (neighborCount: number): boolean =>
12	  neighborCount === 2 || neighborCount === 3;
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  return cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
16	}
